// Created: 2026-05-18

/**
 * Unit tests for lifecycle/hook-token-check (#1860)
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { mkdirSync, mkdtempSync, rmSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { hookTokenCheck, _internals } from '../lifecycle/hook-token-check.js';
import { NOOP_CTX } from '../lib/context.js';
import type { HookInput } from '../types.js';

const ENV_VAR = 'ORCHESTKIT_HOOK_TOKEN';

describe('lifecycle/hook-token-check (#1860)', () => {
  let tmp: string;
  let stderrSpy: ReturnType<typeof vi.spyOn>;
  let originalToken: string | undefined;

  beforeEach(() => {
    tmp = mkdtempSync(join(tmpdir(), 'hook-token-'));
    stderrSpy = vi.spyOn(process.stderr, 'write').mockImplementation(() => true);
    originalToken = process.env[ENV_VAR];
    delete process.env[ENV_VAR];
  });

  afterEach(() => {
    stderrSpy.mockRestore();
    if (originalToken !== undefined) {
      process.env[ENV_VAR] = originalToken;
    } else {
      delete process.env[ENV_VAR];
    }
    try {
      rmSync(tmp, { recursive: true, force: true });
    } catch {
      /* best-effort */
    }
  });

  const inputFor = (projectDir: string): HookInput => ({
    hook_event: 'SessionStart',
    tool_name: '',
    session_id: 'test-session-1860',
    tool_input: {},
    project_dir: projectDir,
  });

  function writeSettings(scope: 'project' | 'home', payload: unknown) {
    const dir =
      scope === 'project' ? join(tmp, '.claude') : join(tmp, 'fakehome', '.claude');
    mkdirSync(dir, { recursive: true });
    writeFileSync(join(dir, 'settings.local.json'), JSON.stringify(payload, null, 2), 'utf8');
  }

  it('exposes the env var name + reference', () => {
    expect(_internals.TOKEN_ENV_VAR).toBe('ORCHESTKIT_HOOK_TOKEN');
    expect(_internals.TOKEN_REFERENCE).toBe('$ORCHESTKIT_HOOK_TOKEN');
  });

  // ---- silent paths ----
  it('returns silent success when token IS set, no scan performed', () => {
    process.env[ENV_VAR] = 'tk_real_token_xyz';
    writeSettings('project', {
      hooks: {
        PreToolUse: [
          {
            type: 'http',
            url: 'https://hq.example.com/api/hooks/cc-event',
            headers: { Authorization: 'Bearer $ORCHESTKIT_HOOK_TOKEN' },
            allowedEnvVars: ['ORCHESTKIT_HOOK_TOKEN'],
          },
        ],
      },
    });

    const result = hookTokenCheck(inputFor(tmp), NOOP_CTX);
    expect(result).toEqual({ continue: true, suppressOutput: true });
    expect(stderrSpy).not.toHaveBeenCalled();
  });

  it('returns silent success when token is empty-string', () => {
    // Whitespace-only must still be treated as unset.
    process.env[ENV_VAR] = '   ';
    const result = hookTokenCheck(inputFor(tmp), NOOP_CTX);
    expect(result).toEqual({ continue: true, suppressOutput: true });
    // No settings files exist → no scans → silent.
    expect(stderrSpy).not.toHaveBeenCalled();
  });

  it('returns silent success when no settings files exist', () => {
    const result = hookTokenCheck(inputFor(tmp), NOOP_CTX);
    expect(result).toEqual({ continue: true, suppressOutput: true });
    expect(stderrSpy).not.toHaveBeenCalled();
  });

  it('returns silent success when settings exist but no hooks reference the token', () => {
    writeSettings('project', {
      hooks: {
        PreToolUse: [
          {
            type: 'http',
            url: 'https://other.example.com/hook',
            headers: { Authorization: 'Bearer $OTHER_TOKEN' },
            allowedEnvVars: ['OTHER_TOKEN'],
          },
        ],
      },
    });

    const result = hookTokenCheck(inputFor(tmp), NOOP_CTX);
    expect(result).toEqual({ continue: true, suppressOutput: true });
    expect(stderrSpy).not.toHaveBeenCalled();
  });

  // ---- warning paths ----
  it('emits stderr banner when token unset and hooks reference it (header form)', () => {
    writeSettings('project', {
      hooks: {
        PreToolUse: [
          {
            type: 'http',
            url: 'https://hq.example.com/api/hooks/cc-event',
            headers: { Authorization: 'Bearer $ORCHESTKIT_HOOK_TOKEN' },
            allowedEnvVars: [],
          },
        ],
      },
    });

    hookTokenCheck(inputFor(tmp), NOOP_CTX);
    expect(stderrSpy).toHaveBeenCalledOnce();
    const banner = String(stderrSpy.mock.calls[0]?.[0] ?? '');
    expect(banner).toMatch(/ORCHESTKIT_HOOK_TOKEN/);
    expect(banner).toMatch(/unset/);
    expect(banner).toMatch(/401/);
    expect(banner).toMatch(/#1860/);
  });

  it('emits stderr banner when reference is via allowedEnvVars only', () => {
    writeSettings('project', {
      hooks: {
        PostToolUse: [
          {
            type: 'http',
            url: 'https://hq.example.com/api/hooks/cc-event',
            headers: { Authorization: 'Bearer ignored' },
            allowedEnvVars: ['ORCHESTKIT_HOOK_TOKEN'],
          },
        ],
      },
    });

    hookTokenCheck(inputFor(tmp), NOOP_CTX);
    expect(stderrSpy).toHaveBeenCalledOnce();
    const banner = String(stderrSpy.mock.calls[0]?.[0] ?? '');
    expect(banner).toMatch(/1 type:http hook entry/);
  });

  it('counts all matching entries across multiple events', () => {
    const sharedEntry = {
      type: 'http' as const,
      url: 'https://hq.example.com/api/hooks/cc-event',
      headers: { Authorization: 'Bearer $ORCHESTKIT_HOOK_TOKEN' },
      allowedEnvVars: ['ORCHESTKIT_HOOK_TOKEN'],
    };
    writeSettings('project', {
      hooks: {
        SessionStart: [sharedEntry],
        PreToolUse: [sharedEntry],
        PostToolUse: [sharedEntry, sharedEntry],
      },
    });

    hookTokenCheck(inputFor(tmp), NOOP_CTX);
    const banner = String(stderrSpy.mock.calls[0]?.[0] ?? '');
    expect(banner).toMatch(/4 type:http hook entries/);
  });

  // ---- robustness ----
  it('survives malformed JSON without throwing', () => {
    const dir = join(tmp, '.claude');
    mkdirSync(dir, { recursive: true });
    writeFileSync(join(dir, 'settings.local.json'), '{ not valid json', 'utf8');

    const result = hookTokenCheck(inputFor(tmp), NOOP_CTX);
    expect(result).toEqual({ continue: true, suppressOutput: true });
    expect(stderrSpy).not.toHaveBeenCalled();
  });

  it('survives non-object input', () => {
    const result = hookTokenCheck(null as unknown as HookInput, NOOP_CTX);
    expect(result).toEqual({ continue: true, suppressOutput: true });
  });
});

describe('lifecycle/hook-token-check internals', () => {
  it('scanSettingsFile returns null for missing file', () => {
    const result = _internals.scanSettingsFile('/nonexistent/path/settings.local.json');
    expect(result).toBeNull();
  });

  it('formatWarning includes path and count', () => {
    const message = _internals.formatWarning([
      { path: '/x/.claude/settings.local.json', count: 3 },
    ]);
    expect(message).toMatch(/3 type:http hook entries/);
    expect(message).toMatch(/x\/\.claude\/settings\.local\.json \(3\)/);
  });
});
